import{c as e,Q as r,j as i,m as t}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"服务特定条款","description":"","frontmatter":{},"headers":[],"relativePath":"tos/service-specific-terms.md","filePath":"tos/service-specific-terms.md","lastUpdated":1779875536000}'),l={name:"tos/service-specific-terms.md"};function n(o,a,h,s,u,c){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="服务特定条款" tabindex="-1">服务特定条款 <a class="header-anchor" href="#服务特定条款" aria-label="Permalink to &quot;服务特定条款&quot;">​</a></h1><p><a href="https://www.suirenai.com" target="_blank" rel="noreferrer">Suirenai Team</a>2025/12/13大约 5 分钟政策</p><hr><p>重要提示</p><p>本文档根据 Suirenai「服务特定条款」页面内容整理（生效日期：2025 年 10 月 30 日）。<br> 如本文档与官网存在差异或版本更新，请以官网页面为准：<br><a href="https://www.suirenai.com/service-specific-terms" target="_blank" rel="noreferrer">https://www.suirenai.com/service-specific-terms</a></p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td>文档名称</td><td>服务特定条款</td></tr><tr><td>生效日期</td><td>2025-10-30</td></tr><tr><td>来源链接</td><td><a href="https://www.suirenai.com/service-specific-terms" target="_blank" rel="noreferrer">https://www.suirenai.com/service-specific-terms</a></td></tr></tbody></table><ul><li><a href="./.html">概述</a></li><li><a href="./suirenai-工作版-团队计划-企业计划.html">A. Suirenai 工作版（团队计划；企业计划）</a></li><li><a href="./.html">B. Beta 服务</a></li><li><a href="./.html">C. 微调服务</a></li><li><a href="./.html">D. 云托管服务</a><ul><li><a href="./.html">一般</a></li><li><a href="./.html">云平台上的内容</a></li><li><a href="./.html">费用</a></li></ul></li><li><a href="./.html">E. 开发合作伙伴计划</a></li><li><a href="./.html">F. API 使用限制</a></li><li><a href="./.html">G. 数据保留</a></li><li><a href="./sla.html">H. 服务级别协议（SLA）</a></li><li><a href="./.html">I. 更新和修改</a></li><li><a href="./.html">相关链接</a></li></ul><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>这些服务特定条款（“服务特定条款”）包含适用于特定服务的补充条款，并构成您或您所代表的组织、公司或其他实体（“客户”）与 Suirenai 就引用或以其他方式引用这些服务特定条款的此类服务（例如商业服务条款）的协议的一部分（“协议”）。这些服务特定条款中未定义的任何大写术语将具有协议中规定的定义。如果条款与这些服务特定条款之间存在任何冲突，这些服务特定条款对相关服务具有控制权。</p><h2 id="a-suirenai-工作版-团队计划-企业计划" tabindex="-1">A. Suirenai 工作版（团队计划；企业计划） <a class="header-anchor" href="#a-suirenai-工作版-团队计划-企业计划" aria-label="Permalink to &quot;A. Suirenai 工作版（团队计划；企业计划）&quot;">​</a></h2><p>客户必须告知其用户 (i) 他们正在访问管理的服务产品，使客户能够访问和控制客户及其用户提交给服务的数据，并且 (ii) 服务的使用受 Suirenai 的政策约束，包括隐私政策和使用政策。客户负责获得任何必要的用户同意并提供适用法律要求的所有用户通知。</p><h2 id="b-beta-服务" tabindex="-1">B. Beta 服务 <a class="header-anchor" href="#b-beta-服务" aria-label="Permalink to &quot;B. Beta 服务&quot;">​</a></h2><p>Suirenai 可能会提供处于预发布、测试、预览或类似试用形式的服务（“Beta 服务”）。这意味着它们不适合生产使用，并按“原样”临时提供。Suirenai 不对客户使用或依赖 Beta 服务负责，也没有义务为其使用提供任何赔偿。Suirenai 对 Beta 服务的责任限于在前 12 个月内客户为服务支付的费用中的较小者 $1,000。</p><h2 id="c-微调服务" tabindex="-1">C. 微调服务 <a class="header-anchor" href="#c-微调服务" aria-label="Permalink to &quot;C. 微调服务&quot;">​</a></h2><p>Suirenai 可能会提供允许客户微调或进行其他形式的模型定制的服务（“微调服务”以及任何此类结果模型，即“微调模型”），包括使用客户提供的数据（“微调材料”）。微调服务使用微调材料来生成或验证微调模型。微调材料是客户内容。客户使用微调服务不构成违反协议中训练禁令；前提是进行的训练仅用于客户使用微调服务。</p><h2 id="d-云托管服务" tabindex="-1">D. 云托管服务 <a class="header-anchor" href="#d-云托管服务" aria-label="Permalink to &quot;D. 云托管服务&quot;">​</a></h2><h3 id="一般" tabindex="-1">一般 <a class="header-anchor" href="#一般" aria-label="Permalink to &quot;一般&quot;">​</a></h3><p>Suirenai 通过以下第三方管理和托管的技术环境提供某些服务：(1) Amazon Bedrock（“Bedrock”），由 Amazon Web Services, Inc. 及其关联公司（“AWS”）托管和管理；以及 (2) Vertex AI（“Vertex”），由 Google LLC 及其关联公司（“Google”）托管和管理。AWS 和 Google 是“云提供商”，其环境是这些服务特定条款的“云平台”。客户承认并同意 Suirenai 不对云平台或客户从云提供商处获得的任何其他服务负责，并且对云平台或其他云提供商服务的更改可能会严重影响客户对服务的使用。客户只能在遵守适用云提供商政策和其与适用云提供商的协议的情况下使用服务。</p><h3 id="云平台上的内容" tabindex="-1">云平台上的内容 <a class="header-anchor" href="#云平台上的内容" aria-label="Permalink to &quot;云平台上的内容&quot;">​</a></h3><p>Suirenai 提供的用于通过云平台访问服务的技术不会使 Suirenai 访问云提供商的任何客户实例，包括它们包含的客户内容。</p><h3 id="费用" tabindex="-1">费用 <a class="header-anchor" href="#费用" aria-label="Permalink to &quot;费用&quot;">​</a></h3><p>客户必须按 Suirenai 当时的费率向适用的云提供商支付通过云平台使用服务相关的所有适用费用和税费，除非各方另有约定。费率更新在适用云提供商或 Suirenai 发布更新后 30 天或客户以其他方式收到通知后的较早日期生效。</p><h2 id="e-开发合作伙伴计划" tabindex="-1">E. 开发合作伙伴计划 <a class="header-anchor" href="#e-开发合作伙伴计划" aria-label="Permalink to &quot;E. 开发合作伙伴计划&quot;">​</a></h2><p>客户可以（自行决定）通过为服务启用许可数据选择加入设置（“开发合作伙伴模式”）来参与开发合作伙伴计划。如果客户启用开发合作伙伴模式，Suirenai 可以在与 Suirenai 的产品和服务相关的情况下使用客户提交给服务的数据（例如，客户内容），包括训练模型。</p><h2 id="f-api-使用限制" tabindex="-1">F. API 使用限制 <a class="header-anchor" href="#f-api-使用限制" aria-label="Permalink to &quot;F. API 使用限制&quot;">​</a></h2><p>客户必须遵守以下 API 使用限制：</p><ul><li><strong>速率限制：</strong> 客户必须遵守 Suirenai 规定的 API 调用速率限制</li><li><strong>配额：</strong> 客户的使用不得超过分配的配额</li><li><strong>缓存：</strong> 客户可以缓存响应，但必须遵守 Suirenai 的缓存政策</li><li><strong>监控：</strong> Suirenai 保留监控 API 使用情况的权利</li></ul><h2 id="g-数据保留" tabindex="-1">G. 数据保留 <a class="header-anchor" href="#g-数据保留" aria-label="Permalink to &quot;G. 数据保留&quot;">​</a></h2><ul><li><strong>客户数据：</strong> 客户数据将根据客户的保留设置进行保留</li><li><strong>备份：</strong> Suirenai 将维护系统备份以确保服务连续性</li><li><strong>删除：</strong> 终止后，客户数据将根据数据处理附录进行处理</li></ul><h2 id="h-服务级别协议-sla" tabindex="-1">H. 服务级别协议（SLA） <a class="header-anchor" href="#h-服务级别协议-sla" aria-label="Permalink to &quot;H. 服务级别协议（SLA）&quot;">​</a></h2><p>Suirenai 致力于提供高可用性服务：</p><ul><li><strong>可用性目标：</strong> 99.9% 的月度正常运行时间</li><li><strong>维护：</strong> 计划维护将提前通知</li><li><strong>支持：</strong> 根据客户计划提供技术支持</li></ul><h2 id="i-更新和修改" tabindex="-1">I. 更新和修改 <a class="header-anchor" href="#i-更新和修改" aria-label="Permalink to &quot;I. 更新和修改&quot;">​</a></h2><p>Suirenai 可能会不时更新这些服务特定条款。重大更改将提前通知客户，并将在通知后 30 天生效。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li>服务条款：<a href="https://www.suirenai.com/terms" target="_blank" rel="noreferrer">https://www.suirenai.com/terms</a></li><li>使用政策（AUP）：<a href="https://www.suirenai.com/usage-policy" target="_blank" rel="noreferrer">https://www.suirenai.com/usage-policy</a></li><li>支持的国家和地区：<a href="https://www.suirenai.com/supported-regions" target="_blank" rel="noreferrer">https://www.suirenai.com/supported-regions</a></li></ul>',36)])])}const m=e(l,[["render",n]]);export{p as __pageData,m as default};
